import React, { useState, useEffect } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Box,
  Button,
  ListItemButton,
  Drawer,
} from "@mui/material";
import {
  MapContainer,
  TileLayer,
  Marker,
  Polyline,
  Popup,
  useMapEvents,
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { createRide, findDrivers } from "../services/api";

export default function Booking() {
  const [pickup, setPickup] = useState(null);
  const [drop, setDrop] = useState(null);
  const [pickupAddress, setPickupAddress] = useState("");
  const [dropAddress, setDropAddress] = useState("");
  const [dropSuggestions, setDropSuggestions] = useState([]);
  const [route, setRoute] = useState(null);
  const [distance, setDistance] = useState(null);

  const [drivers, setDrivers] = useState([]);
  const [currentLocation, setCurrentLocation] = useState(null);

  const [drawerOpen, setDrawerOpen] = useState(false);
  const [rideOptions, setRideOptions] = useState([]);
  const [selectedRide, setSelectedRide] = useState(null);

  const navigate = useNavigate();

  // 📍 Get current location as default pickup
  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setCurrentLocation(loc);
        setPickup(loc);
        const addr = await getAddressFromCoords(loc.lat, loc.lng);
        setPickupAddress(addr);
      },
      (err) => console.error("Geolocation error:", err)
    );
  }, []);

  // 🌍 Reverse geocode
  const getAddressFromCoords = async (lat, lng) => {
    try {
      const res = await axios.get(
        `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`
      );
      return res.data.display_name || "";
    } catch {
      return "";
    }
  };

  // 🔎 Drop suggestions
  const fetchSuggestions = async (query) => {
    if (!query) return;
    try {
      const res = await axios.get("https://nominatim.openstreetmap.org/search", {
        params: { q: query, format: "json", limit: 5 },
      });
      setDropSuggestions(res.data);
    } catch (err) {
      console.error("Suggestion fetch failed:", err);
    }
  };

  // 🛣 Fetch route + distance
  useEffect(() => {
    const fetchRoute = async () => {
      if (pickup && drop) {
        try {
          const res = await axios.get(
            `https://router.project-osrm.org/route/v1/driving/${pickup.lng},${pickup.lat};${drop.lng},${drop.lat}?overview=full&geometries=geojson`
          );
          const data = res.data.routes[0];
          setRoute(data.geometry.coordinates.map((c) => [c[1], c[0]]));
          const km = (data.distance / 1000).toFixed(2);
          setDistance(km);
        } catch (err) {
          console.error("Route fetch failed:", err);
        }
      }
    };
    fetchRoute();
  }, [pickup, drop]);

  // 🚖 Update ride prices dynamically when distance changes
  useEffect(() => {
    if (distance) {
      setRideOptions([
        {
          id: "bike",
          name: "Bike",
          eta: "3 min",
          price: (distance * 10).toFixed(2),
          capacity: 1,
          image: "https://cdn-icons-png.flaticon.com/512/2972/2972185.png",
        },
        {
          id: "auto",
          name: "Auto",
          eta: "2 min",
          price: (distance * 15).toFixed(2),
          capacity: 3,
          image: "https://cdn-icons-png.flaticon.com/512/743/743131.png",
        },
        {
          id: "car",
          name: "Car",
          eta: "4 min",
          price: (distance * 20).toFixed(2),
          capacity: 4,
          image: "https://cdn-icons-png.flaticon.com/512/743/743007.png",
        },
        {
          id: "parcel",
          name: "Parcel",
          eta: "—",
          price: "Go to Parcel Page",
          capacity: "-",
          image: "https://cdn-icons-png.flaticon.com/512/2921/2921222.png",
        },
      ]);
    }
  }, [distance]);

  // 📍 Drop marker by map click
  function LocationMarker() {
    useMapEvents({
      async click(e) {
        setDrop(e.latlng);
        const addr = await getAddressFromCoords(e.latlng.lat, e.latlng.lng);
        setDropAddress(addr);
      },
    });
    return null;
  }

  // 📍 Draggable pickup marker
  function DraggablePickupMarker() {
    return (
      pickup && (
        <Marker
          position={pickup}
          icon={pickupIcon}
          draggable={true}
          eventHandlers={{
            dragend: async (e) => {
              const newPos = e.target.getLatLng();
              setPickup(newPos);
              const addr = await getAddressFromCoords(newPos.lat, newPos.lng);
              setPickupAddress(addr);
            },
          }}
        >
          <Popup>Pickup</Popup>
        </Marker>
      )
    );
  }

  // 🚖 Request ride
  const handleRequestRide = async () => {
    if (selectedRide === "parcel") {
      navigate("/parcel");
      return;
    }

    if (!pickup || !drop || !selectedRide)
      return alert("Select pickup, drop and ride type");

    try {
      const res = await createRide({
        pickup: pickupAddress,
        drop: dropAddress,
        pickupCoords: pickup,
        dropCoords: drop,
        rideType: selectedRide,
      });
      navigate(`/ride/${res.data.ride._id}`);
    } catch (err) {
      alert("Booking failed");
    }
  };

  // 🛻 Find nearby drivers
  const handleFindDrivers = async () => {
    try {
      const res = await findDrivers();
      setDrivers(res.data.drivers || []);
    } catch {
      setDrivers([]);
    }
    setDrawerOpen(true); // open ride options slide
  };

  // Icons
  const pickupIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/32/32339.png",
    iconSize: [25, 25],
  });
  const dropIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/684/684908.png",
    iconSize: [35, 35],
  });
  const driverIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/3103/3103446.png",
    iconSize: [25, 25],
  });
  const currentIcon = new L.DivIcon({
    className: "custom-blue-dot",
    html: `<div style="width:16px;height:16px;background:blue;border-radius:50%;border:2px solid white;"></div>`,
  });

  return (
    <Container maxWidth="xl" sx={{ mt: 3 }}>
      <Box sx={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 2 }}>
        {/* Left panel - Form */}
        <Paper sx={{ p: 3, borderRadius: 2 }}>
          <Typography variant="h6" sx={{ mb: 2 }}>
            Find a trip
          </Typography>

          {/* Pickup auto-filled */}
          <TextField
            fullWidth
            label="Pickup Address"
            value={pickupAddress}
            sx={{ mb: 2 }}
            InputProps={{ readOnly: true }}
          />

          {/* Drop input */}
          <TextField
            fullWidth
            label="Drop Address"
            value={dropAddress}
            onChange={(e) => {
              setDropAddress(e.target.value);
              fetchSuggestions(e.target.value);
            }}
            sx={{ mb: 2 }}
          />
          {dropSuggestions.map((s, i) => (
            <ListItemButton
              key={i}
              onClick={() => {
                setDrop({ lat: parseFloat(s.lat), lng: parseFloat(s.lon) });
                setDropAddress(s.display_name);
                setDropSuggestions([]);
              }}
            >
              {s.display_name}
            </ListItemButton>
          ))}

          <Button
            fullWidth
            variant="contained"
            sx={{ bgcolor: "black", "&:hover": { bgcolor: "#333" }, mt: 2 }}
            onClick={handleFindDrivers}
          >
            Find Riders
          </Button>
        </Paper>

        {/* Right panel - Full Map */}
        <Paper sx={{ p: 1, borderRadius: 2 }}>
          {currentLocation && (
            <MapContainer
              center={currentLocation}
              zoom={13}
              style={{ height: "600px", width: "100%" }}
            >
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <Marker position={currentLocation} icon={currentIcon}>
                <Popup>You are here</Popup>
              </Marker>
              <DraggablePickupMarker />
              {drop && (
                <Marker position={drop} icon={dropIcon}>
                  <Popup>
                    Drop <br /> {distance ? `${distance} km` : ""}
                  </Popup>
                </Marker>
              )}
              <LocationMarker />
              {route && (
                <Polyline
                  positions={route}
                  pathOptions={{ color: "black", weight: 4 }}
                />
              )}
              {drivers.map((d, i) => (
                <Marker key={i} position={d.location} icon={driverIcon} />
              ))}
            </MapContainer>
          )}
        </Paper>
      </Box>

      {/* Slide Drawer for ride options */}
      <Drawer
        anchor="bottom"
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
      >
        <Box sx={{ p: 3 }}>
          <Typography variant="h6" sx={{ mb: 2, fontWeight: "bold" }}>
            Choose a ride
          </Typography>

          {rideOptions.map((opt) => (
            <Box
              key={opt.id}
              onClick={() => setSelectedRide(opt.id)}
              sx={{
                border:
                  selectedRide === opt.id ? "2px solid black" : "1px solid #ccc",
                borderRadius: 2,
                p: 2,
                mb: 2,
                cursor: "pointer",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
              }}
            >
              {/* Left: Image + Info */}
              <Box sx={{ display: "flex", alignItems: "center", gap: 2 }}>
                <img
                  src={opt.image}
                  alt={opt.name}
                  width={50}
                  height={50}
                  style={{ objectFit: "contain" }}
                />
                <Box>
                  <Typography variant="body1" sx={{ fontWeight: "bold" }}>
                    {opt.name} • {opt.capacity} seats
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {opt.eta} • {distance ? `${distance} km` : "—"}
                  </Typography>
                </Box>
              </Box>

              {/* Right: Price */}
              <Typography
                variant="h6"
                sx={{
                  fontWeight: "bold",
                  color: "black",
                  minWidth: "80px",
                  textAlign: "right",
                }}
              >
                {typeof opt.price === "number" || !isNaN(opt.price)
                  ? `₹${opt.price}`
                  : opt.price}
              </Typography>
            </Box>
          ))}

          <Button
            variant="contained"
            fullWidth
            sx={{ mt: 2 }}
            onClick={handleRequestRide}
            disabled={!selectedRide}
          >
            {selectedRide === "parcel"
              ? "Go to Parcel Page"
              : `Request ${
                  selectedRide
                    ? rideOptions.find((r) => r.id === selectedRide).name
                    : ""
                }`}
          </Button>
        </Box>
      </Drawer>
    </Container>
  );
}
